#include <iostream>
#include <string>

class Date {
private:
    int day;
    int month;
    int year;

public:
    Date(int d, int m, int y) : day(d), month(m), year(y) {}

    bool operator==(const Date& other) const {
        if (day != other.day) {
            return false;
        }
        if (month != other.month) {
            return false;
        }
        if (year != other.year) {
            return false;
        }
        return true;
    }

    void print() const {
        std::cout << day << "/" << month << "/" << year;
    }
};

int main() {
    Date d1(1, 1, 2024);
    Date d2(1, 1, 2024);
    Date d3(2, 1, 2024);
    Date d4(1, 2, 2024);

    std::cout << (d1 == d2 ? "true" : "false") << std::endl;
    std::cout << (d1 == d3 ? "true" : "false") << std::endl;
    std::cout << (d1 == d4 ? "true" : "false") << std::endl;

    return 0;
}
